    private static string FormatPrice(decimal price, PricingType pricingType, bool isFree)
    {
        if (isFree || pricingType == PricingType.Free) return "FREE";
        return pricingType switch
        {
            PricingType.Monthly  => $"Rs.{price:N0}/month",
            PricingType.Yearly   => $"Rs.{price:N0}/year",
            PricingType.OneTime  => $"Rs.{price:N0} one-time",
            PricingType.Freemium => price > 0 ? $"Free / Rs.{price:N0}/month" : "Freemium",
            _                    => price > 0 ? $"Rs.{price:N0}" : "FREE"
        };
    }

