    private static readonly List<AIToolDto> _tools = CreateTools();

    public static List<AIToolDto> GetFeaturedTools() => _tools.Where(t => t.IsFeatured).ToList();
    public static List<AIToolDto> GetLatestTools(int count = 12) => _tools.Take(count).ToList();
    public static List<AIToolDto> GetToolsByCategory(int categoryId) => _tools.Where(t => t.CategoryId == categoryId).ToList();
    public static AIToolDto? GetTool(int id) => _tools.FirstOrDefault(t => t.Id == id);

    public static PagedResult<AIToolDto> SearchTools(AIToolSearchDto search)
    {
        var filtered = _tools.AsEnumerable();
        if (!string.IsNullOrWhiteSpace(search.Query))
        {
            var q = search.Query.ToLowerInvariant();
            filtered = filtered.Where(t =>
                t.Name.ToLowerInvariant().Contains(q) ||
                t.Description.ToLowerInvariant().Contains(q) ||
                (t.Tags?.ToLowerInvariant().Contains(q) ?? false) ||
                t.CategoryName.ToLowerInvariant().Contains(q));
        }
        if (search.CategoryId.HasValue)  filtered = filtered.Where(t => t.CategoryId == search.CategoryId.Value);
        if (search.IsFree.HasValue)      filtered = filtered.Where(t => t.IsFree == search.IsFree.Value);
        if (search.IsFeatured.HasValue)  filtered = filtered.Where(t => t.IsFeatured == search.IsFeatured.Value);

        var all  = filtered.ToList();
        var page = Math.Max(1, search.Page);
        var size = Math.Max(1, search.PageSize);
        return new PagedResult<AIToolDto>
        {
            Items      = all.Skip((page - 1) * size).Take(size).ToList(),
            TotalCount = all.Count,
            Page       = page,
            PageSize   = size,
        };
    }
